public class BankAccount {
    private String owner;
    private double balance;
    private int accountNumber;

    // Constructor
    public BankAccount(String owner, int accountNumber, double initialBalance) {
        this.owner = owner;
        this.accountNumber = accountNumber;
        this.balance = (initialBalance >= 0) ? initialBalance : 0;
    }

    // Getter: read-only access to balance
    public double getBalance() {
        return balance;
    }

    // Getter for owner
    public String getOwner() {
        return owner;
    }

    // accountNumber has NO setter — immutable after construction
    public int getAccountNumber() {
        return accountNumber;
    }

    // Setter with validation
    public boolean deposit(double amount) {
        if (amount <= 0) return false;  // reject invalid deposit
        balance += amount;
        return true;
    }

    public boolean withdraw(double amount) {
        if (amount <= 0 || amount > balance) return false;
        balance -= amount;
        return true;
    }

    @Override
    public String toString() {
        return "Account[" + accountNumber + "] " + owner + ": $" + balance;
    }

    public static void main(String[] args) {
        BankAccount acc = new BankAccount("Alice", 1001, 500.0);
        System.out.println(acc.getBalance());       // 500.0
        acc.deposit(200.0);
        System.out.println(acc.getBalance());       // 700.0
        acc.withdraw(1000.0);                       // fails silently
        System.out.println(acc.getBalance());       // 700.0
        System.out.println(acc);                    // Account[1001] Alice: $700.0
    }
}

public class Student {
    private String name;
    private int age;

    // CORRECT: this.name distinguishes field from parameter
    public void setName(String name) {
        this.name = name;  // field = parameter
    }

    // WRONG: name = name assigns the parameter to itself!
    // The field remains unchanged. This is a LOGICAL error.
    public void setNameWrong(String name) {
        name = name;  // Bug: shadowing, field never updated
    }

    public void setAge(int age) {
        if (age >= 0 && age <= 150)
            this.age = age;
    }

    public String getName() { return name; }
    public int getAge() { return age; }

    public static void main(String[] args) {
        Student s = new Student();
        s.setName("Ashik");
        s.setAge(20);
        System.out.println(s.getName() + ", " + s.getAge()); // Ashik, 20

        Student s2 = new Student();
        s2.setNameWrong("Bob");
        System.out.println(s2.getName()); // null  (field was never set!)
    }
}

class Animal {
    private String name;       // not directly accessible in subclasses
    protected int age;         // directly accessible in subclasses
    public String species;     // accessible everywhere

    public Animal(String name, int age, String species) {
        this.name = name;
        this.age = age;
        this.species = species;
    }

    public String getName() { return name; }  // public gateway to private field
}

class Dog extends Animal {
    private String breed;

    public Dog(String name, int age, String breed) {
        super(name, age, "Canine");
        this.breed = breed;
    }

    public void display() {
        // System.out.println(name);  // ERROR: name is private in Animal
        System.out.println(getName());  // OK: using public getter
        System.out.println(age);        // OK: age is protected
        System.out.println(species);    // OK: species is public
        System.out.println(breed);      // OK: own private field
    }
}

public class Main {
    public static void main(String[] args) {
        Dog d = new Dog("Rex", 3, "Labrador");
        d.display();
        // d.name;   // ERROR: private
        // d.age;    // OK (protected, same package)
        // d.breed;  // ERROR: private
    }
}

public final class Point {          // final: can't be subclassed
    private final double x;         // final: must be set in constructor
    private final double y;

    public Point(double x, double y) {
        this.x = x;
        this.y = y;
    }

    public double getX() { return x; }
    public double getY() { return y; }

    // No setters — immutable!
    // To "modify", return a new Point
    public Point translate(double dx, double dy) {
        return new Point(x + dx, y + dy);  // new object, original unchanged
    }

    @Override
    public String toString() {
        return "(" + x + ", " + y + ")";
    }

    public static void main(String[] args) {
        Point p1 = new Point(2.0, 3.0);
        Point p2 = p1.translate(1.0, -1.0);
        System.out.println(p1);  // (2.0, 3.0) — unchanged
        System.out.println(p2);  // (3.0, 2.0)
    }
}

