// Design a class Student with:
// - private fields: name (String), gpa (double), id (int)
// - Constructor: Student(int id, String name, double gpa)
// - Getter for all three fields
// - setGpa(double): only accepts 0.0 to 4.0, otherwise keeps old value
// - toString(): returns "Student{id=X, name=Y, gpa=Z}"
// - main: create Student(101, "Ashik", 3.8), print it,
//         call setGpa(4.5) [rejected], setGpa(3.9) [accepted], print again

sections.solution:
public class Student {
    private int id;
    private String name;
    private double gpa;

    public Student(int id, String name, double gpa) {
        this.id = id;
        this.name = name;
        this.gpa = (gpa >= 0.0 && gpa <= 4.0) ? gpa : 0.0;
    }

    public int getId()     { return id; }
    public String getName(){ return name; }
    public double getGpa() { return gpa; }

    public void setGpa(double gpa) {
        if (gpa >= 0.0 && gpa <= 4.0)
            this.gpa = gpa;
        // else: silently reject, keep old value
    }

    @Override
    public String toString() {
        return "Student{id=" + id + ", name=" + name + ", gpa=" + gpa + "}";
    }

    public static void main(String[] args) {
        Student s = new Student(101, "Ashik", 3.8);
        System.out.println(s);          // Student{id=101, name=Ashik, gpa=3.8}
        s.setGpa(4.5);                  // rejected: 4.5 > 4.0
        s.setGpa(3.9);                  // accepted
        System.out.println(s);          // Student{id=101, name=Ashik, gpa=3.9}
    }
}
